import{_ as a,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"小圣诞树","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/小圣诞树.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/小圣诞树.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/小圣诞树.md"};function l(p,r,_,b,i,c){return t(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"小圣诞树",tabindex:"-1"},[s("小圣诞树 "),e("a",{class:"header-anchor",href:"#小圣诞树","aria-label":'Permalink to "小圣诞树"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),o('<h1 id="小圣诞树-1" tabindex="-1">小圣诞树 <a class="header-anchor" href="#小圣诞树-1" aria-label="Permalink to &quot;小圣诞树&quot;">​</a></h1><p>小圣诞树<br> 本质：特异本质<br> 价格：C+1000<br> 分类：长枪<br> 描述：一颗小小的家庭装饰圣诞树，机缘巧合之下融入了一个孩子的灵魂，于是他想给自己创造一个快乐的圣诞。<br> 伤害：3L<br> 效果：【长柄】、【双手】、【格挡2】、【破甲6】、【威猛6】、【圣诞快乐】、【圣诞老人】</p><p>【圣诞快乐】<br> 这颗圣诞树的使命就是创造一个快乐的圣诞节，但它是个武器，所以它不杀人就不快乐，不快乐就要杀人，而别人不让它杀它会很生气。<br> 当你拿起该武器，你将获得五点不可豁免的亢奋点数；而当敌人将你不留手的攻击出目抵消一半时，你将在接下来五个回合中，对该敌人进行攻击或对抗检定并使用意志力时，额外获得五点表现加值。<br> “嘻嘻，我一定要快乐~”</p><p>【圣诞老人】<br> 再没什么比有一个会实现自己愿望的老爷爷更令人开心的了~<br> 什么？你说圣诞老人不存在？<br> 捅死你捅死你捅死你捅死你捅死你捅死你捅死你捅死你捅死你捅死你捅死你捅死你捅死你捅死你！！！<br> ——因为这样的愿望，被该武器攻击时目标将被夺走五年寿命，倘若目标剩余寿命上限的八分之一不足五年，将按其八分之一计算。<br> “最喜欢圣诞老人啦~”</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=a(d,[["render",l]]);export{f as __pageData,m as default};
